CREATE PROCEDURE [mirae].[SP_MBA200T_BATCH]
(
	@IN_PROCTYPE	VARCHAR(2),				-- 작업구분(Y:작업, N:취소)
	@IN_FRPJTNO		VARCHAR(30),			-- Project Code(From)
	@IN_TOPJTNO		VARCHAR(30),			-- Project Code(To)
	@IN_NEEDDT		VARCHAR(10),			-- 필요일자
	@IN_REQDT		VARCHAR(10),			-- 요청일자
	@IN_REQNO		VARCHAR(30),			-- 구매요청자사번
	@IN_DEPTCD		VARCHAR(20),			-- 구매요청 부서코드
	@IN_ITEMGB		VARCHAR(2),				-- 품목타입(전장, 기구)
	@IN_STOCKYN		VARCHAR(1),				-- 재고감안(X)
	@IN_SAFEYN		VARCHAR(1),				-- 안전재고(X)
	@IN_ITEMCD		VARCHAR(30),			-- 반제품코드
	@IN_ASKGB		VARCHAR(2),				-- 요청사유
	@IN_RMK			VARCHAR(100),			-- 비고
	@O_PO_PLAN_NO	VARCHAR(20) OUTPUT,		-- 작업후 구매요청번호
	@SuccFlag		INT OUTPUT,				-- Error Flag
	@O_ERR_TXT		VARCHAR(300) OUTPUT		-- Error 문
)
AS

SET NOCOUNT ON
BEGIN TRY
	DECLARE @SO_NO			VARCHAR(20),
			@PJT_NO			VARCHAR(30),
			@SO_QTY			NUMERIC,
			@ITEM_GUBUN		VARCHAR(2),
			@BOM_LEVEL		VARCHAR(2),
			@sNextNumber	VARCHAR(20),
			@INextSeq		INTEGER,
			@lLoop			INTEGER;
	DECLARE @CUR_OPEN		INT;
	DECLARE @T_ITEM_CD		VARCHAR(20),
			@C_ITEM_CD		VARCHAR(20),
			@ITEM_CD		VARCHAR(20),
			@UNIT_QTY		NUMERIC,
			@IN_QTY			NUMERIC, 
			@PO_LT			NUMERIC,
			@INV_UNIT		VARCHAR(3)
	DECLARE @lStockQty		NUMERIC;
	DECLARE @lSafeQty		NUMERIC,
	        @ICNT INT;
	DECLARE	@NEED_QTY		NUMERIC,
			@REQ_QTY		NUMERIC,
			@CHANGE_QTY		NUMERIC;
	DECLARE @QC_KIND		VARCHAR(1);

	SET @lStockQty	= 0;
	SET @lSafeQty	= 0;
	
	SET @SuccFlag	= 0;
	SET @O_ERR_TXT = '';
	
	IF @IN_PROCTYPE = 'Y'
		BEGIN
			-- 0.해당프로젝트의 수주상태가 종료인가를 체크 함('ZZ')
			SELECT	@ICNT = ISNULL(COUNT(*),0)
			  FROM  SCA200T
			 WHERE  PJT_NO	>=     @IN_FRPJTNO
		  	   AND  PJT_NO	<=     @IN_TOPJTNO
			   AND  SO_STS	=       'ZZ';
			
			IF @ICNT > 0 
				BEGIN
					SET @O_ERR_TXT = '범위에 종료된 프로젝트가 있습니다. 더 이상 구매요청을 진행할 수 없습니다.';
					SET @SuccFlag = -1;
					RAISERROR(@O_ERR_TXT, 16,0);
				END
			
			-- 0.해당프로젝트의 BOM정보 존재 여부 체크	
		    SELECT	@ICNT = ISNULL(COUNT(*),0) 
		      FROM	BBA020T
		     WHERE  P_ITEM_CD	>=     @IN_FRPJTNO
			   AND  P_ITEM_CD	<=     @IN_TOPJTNO
			
			IF @ICNT = 0  
			   BEGIN
					SET @O_ERR_TXT = 'BOM정보가 없는 프로젝트가 있습니다.';
					SET @SuccFlag = 1;
					RAISERROR(@O_ERR_TXT, 16,0);
				END
			
			-- 1.해당프로젝트의 수주상태가 종료인가를 체크 함('ZZ')
			SELECT	@SO_NO = SO_NO, @PJT_NO = PJT_NO
			FROM    SCA200T
			WHERE   PJT_NO	>=     @IN_FRPJTNO
			AND     PJT_NO	<=     @IN_TOPJTNO;
			
			-- 2.프로젝트 수주 여부 검사(SO_NO, PJT_NO)
			-- 구매요청번호 자동생성	
			EXEC SP_GETNEXTNUMBER 'PR',@IN_REQDT,'MBA200T','PO_PLAN_NO', @sNextNumber OUTPUT, @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
			IF @SuccFlag <> '0'
				BEGIN
					RAISERROR (@O_ERR_TXT, 16, 0);
					END
			SET @INextSeq = 0;
			SET @lLoop  = 0;
				
			DECLARE MBA_REC CURSOR FOR			
				SELECT	A.SO_NO, A.PJT_NO, A.SO_QTY, B.ITEM_GUBUN, C.BOM_LEVEL
				 FROM	SCA200T A
						INNER JOIN BBA010T B
						ON  A.PJT_NO = B.ITEM_CD
						INNER JOIN BAA060T C
						ON  A.MODEL_NO = C.MODEL
				 WHERE	A.PJT_NO >= @IN_FRPJTNO
				 AND	A.PJT_NO <= @IN_TOPJTNO
				 ORDER	BY PJT_NO;
			 
			OPEN MBA_REC;
			FETCH NEXT FROM MBA_REC	
			INTO @SO_NO, @PJT_NO, @SO_QTY, @ITEM_GUBUN, @BOM_LEVEL;
			
			WHILE @@FETCH_STATUS = 0
				BEGIN
			
					EXEC SP_SetExpandedBOMNew @PJT_NO, @IN_ITEMCD, @BOM_LEVEL, @SO_QTY, @IN_ITEMGB, '', @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
					IF @@ERROR <> 0 or @O_ERR_TXT <> ''
						BEGIN	
							SET @O_ERR_TXT = @O_ERR_TXT;
							RAISERROR(@O_ERR_TXT, 16,0);
						END
					--/*
					--DECLARE BBA_REC1 CURSOR FOR
					
					--	SELECT	A.T_ITEM_CD,    A.C_ITEM_CD,    A.ITEM_CD,  A.UNIT_QTY,
					--			ISNULL(B.IN_QTY, 0) AS IN_QTY,  C.PO_LT,    C.INV_UNIT
					--	FROM	BBA022T A
					--			LEFT OUTER JOIN (SELECT T_ITEM_CD, P_ITEM_CD, ITEM_CD, SUM(REQ_QTY + STOCK_QTY) AS IN_QTY 
					--							 FROM MBA210T WHERE PJT_NO = @PJT_NO GROUP BY PJT_NO, T_ITEM_CD, P_ITEM_CD, ITEM_CD)B
					--			ON  A.T_ITEM_CD = B.T_ITEM_CD
					--			AND A.C_ITEM_CD = B.P_ITE

