-- exec SP_MBA200T_OUT_BATCH '*1206006', '1', '20120621', '20120620', '9999994', '3200', '', 0, ''
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	예외발주PJT, 차수별 구매요청등록
-- =============================================
CREATE PROCEDURE [mirae].[SP_MBA200T_OUT_BATCH]
	@IN_PJTNO		VARCHAR(30),	-- 프로젝트번호
	@IN_TITEMCD		VARCHAR(30),	-- SUB UNIT		TODO : 2012.11.14 ADD
	@IN_CHA			VARCHAR(02),	-- 차수
	@IN_NEEDDT		VARCHAR(10),	-- 필요일
	@IN_REQDT		VARCHAR(10),	-- 구매요청일
	@IN_REQNO		VARCHAR(30),	-- 구매요청자
	@IN_DEPTCD		VARCHAR(20),	-- 구매요청부서
	@IN_REMARK		VARCHAR(200),	-- 비고
	@O_PO_PLAN_NO	VARCHAR(20) OUTPUT,
	@SuccFlag		INT OUTPUT,
	@O_ERR_TXT		VARCHAR(300) OUTPUT
AS

--SET NOCOUNT ON
BEGIN TRY
	DECLARE @SO_NO				VARCHAR(20),
			@SO_QTY				NUMERIC,
			@sNextNumber		VARCHAR(20),
			@INextSeq			INTEGER,
			@C1_PJT_NO			VARCHAR(30),
			@C1_T_ITEM_CD		VARCHAR(20),
			@C1_P_ITEM_CD		VARCHAR(20),
			@C1_ITEM_CD			VARCHAR(20),
			@C1_UNIT_QTY		NUMERIC,
			@C1_IN_QTY			NUMERIC, 
			@C1_PO_LT			NUMERIC,
			@C1_INV_UNIT		VARCHAR(3),
	        @ICNT INT;
	                                
	SET @SuccFlag	= 0;
	SET @O_ERR_TXT = '';

	-- 1.해당프로젝트의 수주상태가 종료인가를 체크 함('ZZ')
	set @ICNT = 0;
	SELECT     @ICNT = COUNT(*)
	FROM       SCA200T
	WHERE      PJT_NO	=     @IN_PJTNO
	AND        SO_STS	=       'ZZ';

	IF @ICNT > 0
		BEGIN
			SET @O_ERR_TXT = '이 프로젝트는 종료된 프로젝입니다. 더이상 구매요청을 진행할수 없습니다.';
			SET @SuccFlag = 1;
			RAISERROR(@O_ERR_TXT, 16,0);
			
		END
	
	-- 수주번호, 수량 가져오기
	SELECT     @SO_NO = SO_NO, @SO_QTY = SO_QTY
	FROM       SCA200T
	WHERE      PJT_NO	=     @IN_PJTNO;

 	-- 2.Bom존재하는지 여부
	SET @ICNT = 0;
	SELECT @ICNT = ISNULL(COUNT(*),0) FROM BBA350T
    WHERE   PJT_NO		=	@IN_PJTNO
    AND		T_ITEM_CD	=	@IN_TITEMCD			-- TODO : 2012.11.14 ADD
	AND     BOM_CH		=	@IN_CHA
	
	IF @ICNT = 0  
	   BEGIN
			SET @O_ERR_TXT = '해당 프로젝트의 BOM정보가 없습니다.';
			SET @SuccFlag = -1;
			RAISERROR(@O_ERR_TXT, 16,0);
		END

	-- 3.구매요청번호 자동생성	
	EXEC SP_GETNEXTNUMBER 'PR',@IN_REQDT,'MBA200T','PO_PLAN_NO', @sNextNumber OUTPUT, @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
	
	-- 4.Bom Select
	SET @INextSeq = 0;

	DECLARE BBA_REC1 CURSOR FOR
		SELECT	A.PJT_NO, 
				A.T_ITEM_CD, A.T_ITEM_CD AS P_ITEM_CD,		
				A.ITEM_CD, 
				SUM(A.UNIT_QTY) AS UNIT_QTY, 
				MAX(ISNULL(B.IN_QTY, 0)) AS IN_QTY, 
				C.PO_LT, 
				C.INV_UNIT
		FROM	BBA350T A
				LEFT OUTER JOIN (
								 SELECT PJT_NO, T_ITEM_CD, P_ITEM_CD, ITEM_CD, SUM(REQ_QTY + STOCK_QTY) AS IN_QTY 
								 FROM MBA210T WHERE PJT_NO = @IN_PJTNO
								 AND T_ITEM_CD = @IN_TITEMCD			-- TODO : 2012.11.14 ADD
								 GROUP BY PJT_NO, T_ITEM_CD, P_ITEM_CD, ITEM_CD
								 ) B
				ON  A.PJT_NO	= B.PJT_NO
				AND	A.T_ITEM_CD = B.T_ITEM_CD	-- TODO : 2012.11.14 ADD
				AND A.ITEM_CD   = B.ITEM_CD
				--AND A.P_ITEM_CD   = B.P_ITEM_CD
				INNER JOIN BBA010T C
				ON  A.ITEM_CD	= C.ITEM_CD
				AND ITEM_ACCNT <> '30'
				 AND SUPPLY_TYPE <> 'WO'
		WHERE	A.PJT_NO	= @IN_PJTNO
		AND		A.T_ITEM_CD = @IN_TITEMCD			-- TODO : 2012.11.14 ADD
		AND		A.BOM_CH	= @IN_CHA
		AND		A.USE_YN = 'Y'
		GROUP BY A.PJT_NO, A.T_ITEM_CD, A.ITEM_CD, C.PO_LT, C.INV_UNIT;
	OPEN BBA_REC1
	FETCH NEXT FROM BBA_REC1 INTO @C1_PJT_NO, @C1_T_ITEM_CD, @C1_P_ITEM_CD, @C1_ITEM_CD, @C1_UNIT_QTY, @C1_IN_QTY, @C1_PO_LT, @C1_INV_UNIT
		
	WHILE @@FETCH_STATUS = 0
		BEGIN
			SET @INextSeq = @INextSeq +1;
			INSERT INTO MBA210T
						(PO_PLAN_NO,            SO_NO,				PJT_NO,
						PO_PLAN_SEQ,            T_ITEM_CD,
						P_ITEM_CD,              ITEM_CD,			COMP_QTY,       NEED_QTY,
						STOCK_QTY,              SAFETY_QTY,			IN_QTY,         REQ_QTY,
						NEED_DT,                PO_PLAN_STS,		DVRY_DT,        PO_UNIT,
						PO_PLAN_KIND,           CHANGE_QTY,			REMARK)
						VALUES     
						(@sNextNumber,			@SO_NO,				@C1_PJT_NO,
						@INextSeq ,				@C1_T_ITEM_CD,
						@C1_P_ITEM_CD,				@C1_ITEM_CD,

