	IF (@SO_QTY <= 0)
		BEGIN
			SET @O_ERR_TXT = '수주 수량이 0보다 작은 경우, 구매요청을 진행할 수 없습니다. 수주 수량을 확인해 주세요.';
			SET @SuccFlag = 1;
			RAISERROR(@O_ERR_TXT, 16,0);
		END

 	-- 2.Bom존재하는지 여부
	SET	@ICNT	=	0;
	SELECT	@ICNT	=	ISNULL(COUNT(*), 0)
	FROM	BBA650T
    WHERE	PJT_NO		=	@IN_PJTNO
    AND		T_ITEM_CD	=	@IN_TITEMCD
	AND		BOM_CH		=	@IN_CHA;
	IF @ICNT = 0  
	   BEGIN
			SET @O_ERR_TXT = '해당 프로젝트의 BOM 정보가 없습니다.';
			SET @SuccFlag = -1;
			RAISERROR(@O_ERR_TXT, 16,0);
		END

	-- 3.구매요청번호 자동생성	
	EXEC SP_GETNEXTNUMBER 'PR', @IN_REQDT,'MBA200T', 'PO_PLAN_NO', @sNextNumber OUTPUT, @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
	
	-- 4.Bom Select
	SET @INextSeq = 0;

	DECLARE BBA_REC1 CURSOR FOR
		SELECT	A.PJT_NO, 
			--	A.T_ITEM_CD, A.T_ITEM_CD AS P_ITEM_CD, -- A.P_ITEM_CD,		
				A.T_ITEM_CD, A.P_ITEM_CD,		
				A.ITEM_CD, 
				SUM(A.UNIT_QTY) AS UNIT_QTY, 
				MAX(ISNULL(B.IN_QTY, 0)) AS IN_QTY, 
				C.PO_LT, 
				C.INV_UNIT,
				C.QC_KIND,
				A.REV
		FROM	BBA650T A
				LEFT OUTER JOIN (
								 SELECT PJT_NO, T_ITEM_CD, P_ITEM_CD, ITEM_CD, SUM(REQ_QTY + STOCK_QTY) AS IN_QTY 
								 FROM MBA210T WHERE PJT_NO = @IN_PJTNO
								 AND T_ITEM_CD = @IN_TITEMCD			-- TODO : 2012.11.14 ADD
								 GROUP BY PJT_NO, T_ITEM_CD, P_ITEM_CD, ITEM_CD
								 ) B
				ON  A.PJT_NO	= B.PJT_NO
				AND	A.T_ITEM_CD = B.T_ITEM_CD
				AND	A.P_ITEM_CD = B.P_ITEM_CD
				AND A.ITEM_CD   = B.ITEM_CD
				INNER JOIN BBA010T C
				ON  A.ITEM_CD	= C.ITEM_CD
				--AND ITEM_ACCNT <> '30'  --lcj 2017 10.10 반제품 발주가능
				 AND SUPPLY_TYPE <> 'WO'
		WHERE	A.PJT_NO	= @IN_PJTNO
		AND		A.T_ITEM_CD = @IN_TITEMCD
		AND		A.BOM_CH	= @IN_CHA
		AND		A.USE_YN = 'Y'
		GROUP BY A.PJT_NO, A.T_ITEM_CD, A.P_ITEM_CD, A.ITEM_CD, C.PO_LT, C.INV_UNIT, C.QC_KIND, A.REV;
	
	OPEN BBA_REC1;

	FETCH NEXT FROM BBA_REC1 INTO @C1_PJT_NO, @C1_T_ITEM_CD, @C1_P_ITEM_CD, @C1_ITEM_CD, @C1_UNIT_QTY, @C1_IN_QTY, @C1_PO_LT, @C1_INV_UNIT, @C1_QC_KIND, @C1_REV;
		
	WHILE @@FETCH_STATUS = 0
		BEGIN
			SET @INextSeq = @INextSeq +1;
			INSERT INTO MBA210T
						(PO_PLAN_NO,            SO_NO,				PJT_NO,
						PO_PLAN_SEQ,            T_ITEM_CD,
						P_ITEM_CD,              ITEM_CD,			COMP_QTY,       NEED_QTY,
						STOCK_QTY,              SAFETY_QTY,			IN_QTY,         REQ_QTY,
						NEED_DT,                PO_PLAN_STS,		DVRY_DT,        PO_UNIT,
						PO_PLAN_KIND,           CHANGE_QTY,			REMARK,			QC_KIND,
						REV)
						VALUES     
						(@sNextNumber,			@SO_NO,				@C1_PJT_NO,
						@INextSeq ,				@C1_T_ITEM_CD,
						@C1_P_ITEM_CD,				@C1_

proc_SP_MBA200T_QTY_CHK:
-- -----------------------
-- BOM 사용 안함 수량 SELECT
-- ------------------------
--EXEC [mirae].[SP_MBA200T_QTY_CHK] 'SCL05002','SCL05002','',''
CREATE PROCEDURE [mirae].[SP_MBA200T_QTY_CHK]
(	
	@IN_FRPJTNO		VARCHAR(30),			-- Project Code(From)
	@IN_TOPJTNO		VARCHAR(30),			-- Project Code(To)	
	@SuccFlag		INT OUTPUT,				-- Error Flag
	@O_ERR_TXT		VARCHAR(300) OUTPUT		-- Error 문
)
AS

SET NOCOUNT ON
BEGIN TRY
	DECLARE @SO_NO			VARCHAR(20),
			@PJT_NO			VARCHAR(30),
			@SO_QTY			NUMERIC,
			@ITEM_GUBUN		VARCHAR(2),
			@BOM_LEVEL		VARCHAR(2),
			@sNextNumber	VARCHAR(20),
			@INextSeq		INTEGER,
			@lLoop			INTEGER;
	DECLARE @CUR_OPEN		INT;
	DECLARE @T_ITEM_CD		VARCHAR(20),
			@C_ITEM_CD		VARCHAR(20),
			@ITEM_CD		VARCHAR(20),
			@UNIT_QTY		NUMERIC,
			@IN_QTY			NUMERIC, 
			@PO_LT			NUMERIC,
			@INV_UNIT		VARCHAR(3)
	DECLARE @lStockQty		NUMERIC;
	DECLARE @lSafeQty		NUMERIC,
	        @ICNT INT;
	                                
	SET @lStockQty	= 0;
	SET @lSafeQty	= 0;
	
	SET @SuccFlag	= 0;
	SET @O_ERR_TXT = '';	
	
				
	DECLARE MBA_REC CURSOR FOR			
		SELECT	A.SO_NO, A.PJT_NO, A.SO_QTY, B.ITEM_GUBUN, C.BOM_LEVEL
		 FROM	SCA200T A
				INNER JOIN BBA010T B
				ON  A.PJT_NO = B.ITEM_CD
				INNER JOIN BAA060T C
				ON  A.MODEL_NO = C.MODEL
		 WHERE	A.PJT_NO >= @IN_FRPJTNO
		 AND	A.PJT_NO <= @IN_TOPJTNO
		 ORDER	BY PJT_NO;
	 
	OPEN MBA_REC;
	FETCH NEXT FROM MBA_REC	
	INTO @SO_NO, @PJT_NO, @SO_QTY, @ITEM_GUBUN, @BOM_LEVEL;
	
	WHILE @@FETCH_STATUS = 0
		BEGIN
	
			EXEC SP_SetExpandedBOMNew_CHK @PJT_NO, '', @BOM_LEVEL, @SO_QTY, '', '', @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
		--	EXEC SP_SetExpandedBOMNew @PJT_NO, @IN_ITEMCD, @BOM_LEVEL, @SO_QTY, @IN_ITEMGB, '', @SuccFlag OUTPUT, @O_ERR_TXT OUTPUT;
			IF @@ERROR <> 0 or @O_ERR_TXT <> ''
				BEGIN	
					SET @O_ERR_TXT = @O_ERR_TXT;
					RAISERROR(@O_ERR_TXT, 16,0);
				END
			
			SELECT * FROM  BBA022T;
			
			SET @lLoop = @lLoop +1;
			FETCH NEXT FROM MBA_REC	
			INTO @SO_NO, @PJT_NO, @SO_QTY, @ITEM_GUBUN, @BOM_LEVEL;
		END
		
		CLOSE MBA_REC;
		DEALLOCATE MBA_REC;

END TRY 
BEGIN CATCH
	
	SELECT @ICNT = CURSOR_STATUS('global','MBA_REC');
	IF @ICNT = 1
	BEGIN 
		CLOSE MBA_REC;
		DEALLOCATE MBA_REC;
	END;

	SET @SuccFlag = 1;
	
    SELECT @SuccFlag  = 1, @O_ERR_TXT =  '에러메시지 : ' + ERROR_MESSAGE() + char(13)+char(10)
								       + '에러행번호 : ' + CAST(error_line() as varchar)  + char(13)+char(10)
								       + '에러 프로시저 : ' + ISNULL(error_procedure(), '없음');                	
END CATCH
